SELECT

FROM leave_applications l
JOIN users s ON l.student_id = s.id
LEFT JOIN student_profiles sp ON s.id = sp.user_id
LEFT JOIN users a ON l.auditor_id = a.id
WHERE l.student_id = #{studentId}

    AND l.status = #{status}

ORDER BY l.created_at DESC, l.id DESC
LIMIT #{offset}, #{pageSize}

SELECT COUNT(*)
FROM leave_applications
WHERE student_id = #{studentId}

    AND status = #{status}

SELECT

FROM leave_applications l
JOIN users s ON l.student_id = s.id
LEFT JOIN student_profiles sp ON s.id = sp.user_id
LEFT JOIN users a ON l.auditor_id = a.id
WHERE l.college = #{college}

    AND l.status = #{status}


    AND s.real_name LIKE CONCAT('%', #{studentName}, '%')

ORDER BY l.created_at DESC, l.id DESC
LIMIT #{offset}, #{pageSize}

SELECT COUNT(*)
FROM leave_applications l
JOIN users s ON l.student_id = s.id
WHERE l.college = #{college}

    AND l.status = #{status}


    AND s.real_name LIKE CONCAT('%', #{studentName}, '%')

mapper.update:
UPDATE leave_applications
SET status = 'CANCELED'
WHERE id = #{id}
  AND student_id = #{studentId}
  AND status = 'PENDING'

UPDATE leave_applications
SET status = 'RETURNED',
    return_time = NOW()
WHERE id = #{id}
  AND student_id = #{studentId}
  AND status = 'APPROVED'
